        parameter_name: goalEventCreateDraft.parameter_name.trim(),
        min_relative_lift:
          goalEventCreateDraft.metric_role === 'guardrail'
            ? Number(goalEventCreateDraft.min_relative_lift ?? -10)
            : existingPreset.min_relative_lift,
